// Get the base idea from the previous node
const baseIdea = $input.first().json.output;

// Output 3 distinct items. The AI Agent will run once for each.
return [
  { json: { angle: "A step-by-step How-To guide", content: baseIdea } },
  { json: { angle: "A Contrarian, opinionated take", content: baseIdea } },
  { json: { angle: "A data-driven Case Study", content: baseIdea } }
];

// 1. Grab the master request ID from the Webhook
const requestId = $('Extraction Webhook').first().json.body[0].request_id;

// 2. Process all 3 items (mapping to the 'output' key you provided)
return $input.all().map((item, index) => {
  const rawMarkdown = item.json.output || "";

  // --- Angle Priority Logic ---
  // We check for "Case Study" and "Contrarian" BEFORE "How-To"
  let detectedAngle = "SEO Article"; 
  const lower = rawMarkdown.toLowerCase();

  if (lower.includes("case study") || lower.includes("data-driven")) {
    detectedAngle = "Case Study";
  } else if (lower.includes("contrarian") || lower.includes("opinionated")) {
    detectedAngle = "Contrarian";
  } else if (lower.includes("step-by-step") || lower.includes("how-to")) {
    detectedAngle = "How-To Guide";
  }

  // --- Title & Image Prompt Extraction ---
  const titleMatch = rawMarkdown.match(/^#\s+(.*)/m);
  const title = titleMatch ? titleMatch[1] : "Untitled Draft";
  const imageMatch = rawMarkdown.match(/!\[Image:\s*(.*?)\]/);
  const semanticPrompt = imageMatch ? imageMatch[1] : "Professional B2B SaaS illustration";

  // --- Body Cleaning ---
  const cleanBody = rawMarkdown
    .replace(/^#\s+.*\n?/, '')      // Removes H1
    .replace(/!\[Image:.*?\]/g, '') // Removes ![Image] tag
    .trim();

  // Return as separate items so OpenAI/GDrive run 3 times
  return {
    json: {
      request_id: requestId, // Passed through for the final wrap
      id: `draft_${index + 1}_${Date.now()}`,
      title: title.trim(),
      angle: detectedAngle,
      body: cleanBody,
      image_prompt: `High-quality, professional, minimalist Vercel-style graphic: ${semanticPrompt}`,
      word_count: cleanBody.split(/\s+/).filter(x => x.length > 0).length
    }
  };
});

let finalContent = "";

// 1. Try to get content from HTTP Request
try {
  finalContent = $('Query Content From URL').first().json.data.content;
} catch (e) {
  // Node might not have run, moving on...
}

// 2. If empty, try to get from Extraction Webhook
if (!finalContent || finalContent === "") {
  try {
    // Handling the array [0] safely
    finalContent = $('Set Raw Content').first().json.content;
  } catch (e) {
    // Node might not have run
  }
}

return {
  unified_content: finalContent || "No content detected",
  source: finalContent ? "Success" : "Empty"
};

