return $input.all().map(item => {
  try {
    // 1. Convert the raw text string into a Javascript Object
    const parsedData = JSON.parse(item.json.text);

    // 2. Return the clean validation properties
    return {
      is_valid: parsedData.is_valid,
      reasoning: parsedData.reasoning
    };
  } catch (error) {
    // 3. Safety fallback if the LLM fails to return valid JSON
    return {
      is_valid: false,
      reasoning: "CRITICAL: The validator output was not valid JSON."
    };
  }
});
